import{_ as e,c as t,o as s,ae as n}from"./chunks/framework.Dh1jimFm.js";const u=JSON.parse('{"title":"HTML5新特性 -- 经典篇","description":"","frontmatter":{},"headers":[],"relativePath":"document/Html/Html5新特性.md","filePath":"document/Html/Html5新特性.md"}'),l={name:"document/Html/Html5新特性.md"};function i(p,a,o,r,d,c){return s(),t("div",null,a[0]||(a[0]=[n(`<h1 id="html5新特性-经典篇" tabindex="-1">HTML5新特性 -- 经典篇 <a class="header-anchor" href="#html5新特性-经典篇" aria-label="Permalink to &quot;HTML5新特性 -- 经典篇&quot;">​</a></h1><h2 id="语义化标签" tabindex="-1">语义化标签 <a class="header-anchor" href="#语义化标签" aria-label="Permalink to &quot;语义化标签&quot;">​</a></h2><p>header、nav、footer、aside、section 对seo友好</p><h2 id="dom查询操作" tabindex="-1">DOM查询操作 <a class="header-anchor" href="#dom查询操作" aria-label="Permalink to &quot;DOM查询操作&quot;">​</a></h2><p>document.querySelector()、document.querySelectorAll()</p><h2 id="表单控件" tabindex="-1">表单控件 <a class="header-anchor" href="#表单控件" aria-label="Permalink to &quot;表单控件&quot;">​</a></h2><p>calendar、date、time、email、url、search input的新增type属性</p><h2 id="拖曳api" tabindex="-1">拖曳API <a class="header-anchor" href="#拖曳api" aria-label="Permalink to &quot;拖曳API&quot;">​</a></h2><p>drag、drop 使一个H5元素变为可拖曳</p><h2 id="音频、视频api" tabindex="-1">音频、视频API <a class="header-anchor" href="#音频、视频api" aria-label="Permalink to &quot;音频、视频API&quot;">​</a></h2><p>audio、video</p><h2 id="画布api" tabindex="-1">画布API <a class="header-anchor" href="#画布api" aria-label="Permalink to &quot;画布API&quot;">​</a></h2><p>canvas元素用于图形的绘制。标签只是图形容器，需要通过脚本（通常是JavaScript）来完成图形绘制</p><h2 id="地理api" tabindex="-1">地理API <a class="header-anchor" href="#地理api" aria-label="Permalink to &quot;地理API&quot;">​</a></h2><p>Geolocation</p><h2 id="web存储" tabindex="-1">Web存储 <a class="header-anchor" href="#web存储" aria-label="Permalink to &quot;Web存储&quot;">​</a></h2><p>本地离线存储 localStorage：长期存储，路蓝旗关闭后数据不丢失 本地会话存储 sessionStorage：在浏览器关闭后自动删除</p><h2 id="离线存储" tabindex="-1">离线存储 <a class="header-anchor" href="#离线存储" aria-label="Permalink to &quot;离线存储&quot;">​</a></h2><p>概念：在用户没有因特网连接时，可以正常访问站点或应用，在用户连接因特网时，更新用户机器上的缓存文件</p><p>原理：HTML5的离线存储是基于一个新建的.appcache文件的缓存机制(不是存储技术)，通过这个文件上的解析清单来离线存储资源，这些资源就会像cookie一样被存储下来，之后网络断开时，浏览器会使用这些被离线存储的数据进行展示 使用方法：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;!-- 创建一个和 html 同名的 manifest 文件，然后在页面头部加入 manifest 属性： --&gt;</span></span>
<span class="line"><span>&lt;html lang=&quot;en&quot; manifest=&quot;index.manifest&quot;&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;!-- 在 cache.manifest 文件中编写需要离线存储的资源： --&gt;</span></span>
<span class="line"><span>CACHE MANIFEST</span></span>
<span class="line"><span>    #v0.11</span></span>
<span class="line"><span>    CACHE:</span></span>
<span class="line"><span>    js/app.js</span></span>
<span class="line"><span>    css/style.css</span></span>
<span class="line"><span>    NETWORK:</span></span>
<span class="line"><span>    resourse/logo.png</span></span>
<span class="line"><span>    FALLBACK:</span></span>
<span class="line"><span>    / /offline.html</span></span></code></pre></div><h2 id="其它新技术" tabindex="-1">其它新技术 <a class="header-anchor" href="#其它新技术" aria-label="Permalink to &quot;其它新技术&quot;">​</a></h2><h3 id="webworker" tabindex="-1">webworker <a class="header-anchor" href="#webworker" aria-label="Permalink to &quot;webworker&quot;">​</a></h3><p>JS的JS引擎线程为主线程，在JS引擎线程执行脚本时，页面的GUI渲染线程是被阻塞的；web worker线程独立于JS引擎线程，可以运行JS脚本，但获取不到window对象，适合复杂JS运算，数据结果可以通过postMessage传回主线程(JS引擎线程)</p><h3 id="websocket" tabindex="-1">websocket <a class="header-anchor" href="#websocket" aria-label="Permalink to &quot;websocket&quot;">​</a></h3><p>概念：WebSocket是HTML5提供的一种在单个TCP连接上进行全双工通讯的协议（双向通信协议），协议标识符是ws/wss 作用：实现客户端与服务器之间的双向通信，允许服务端主动向客户端推送数据，只需一次握手，就可以建立持久性连接，进行双向数据传输</p><h2 id="html5新特性-实用篇" tabindex="-1">HTML5新特性 -- 实用篇 <a class="header-anchor" href="#html5新特性-实用篇" aria-label="Permalink to &quot;HTML5新特性 -- 实用篇&quot;">​</a></h2><h3 id="detail-tag" tabindex="-1">detail tag <a class="header-anchor" href="#detail-tag" aria-label="Permalink to &quot;detail tag&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;details&gt;标签提供随需应变的细节内容给用户。如果需要按需向用户显示内容，请使用此标记。默认情况下，详细内容是关闭的。打开后，它将展开并显示其中的内容。</span></span>
<span class="line"><span>&lt;summary&gt;标签与&lt;details&gt;一起使用，来为它指定一个可见的标题。</span></span></code></pre></div><h3 id="content-editable" tabindex="-1">Content Editable <a class="header-anchor" href="#content-editable" aria-label="Permalink to &quot;Content Editable&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>contenteditable是可以在元素上设置以使内容可编辑的属性</span></span>
<span class="line"><span>可以与DIV，P，UL等元素一起使用。您必须像这样指定它：&lt;element contenteditable=&quot;true|false&quot;&gt;。</span></span>
<span class="line"><span>注意，如果contenteditable未在元素上设置属性，则会从其父级继承该属性。</span></span>
<span class="line"><span>可以用input事件监听修改操作</span></span></code></pre></div><h3 id="map" tabindex="-1">Map <a class="header-anchor" href="#map" aria-label="Permalink to &quot;Map&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;map&gt;标签可以帮助定义image map，image map是其中具有一个或多个可单击区域的任何图像。map标签与&lt;area&gt;标签一起确定可点击区域。可点击区域可以是矩形，圆形或多边形区域中的任意一种。如果您未指定任何形状，它将默认整个图像。</span></span></code></pre></div><h3 id="mark-content" tabindex="-1">Mark Content <a class="header-anchor" href="#mark-content" aria-label="Permalink to &quot;Mark Content&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用&lt;mark&gt;标记突出显示任何文本内容。</span></span></code></pre></div><h3 id="data-attribute" tabindex="-1">data-*attribute <a class="header-anchor" href="#data-attribute" aria-label="Permalink to &quot;data-*attribute&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>data-*属性用于存储页面或应用程序专用的自定义数据。可以在Javascript代码中使用存储的数据来创建更多的用户体验。</span></span>
<span class="line"><span>data-*属性由两部分组成：</span></span>
<span class="line"><span>  1.属性名称不得包含任何大写字母，并且前缀&quot;data-&quot;后必须至少长一个字符</span></span>
<span class="line"><span>  2.属性值可以是任何字符串</span></span>
<span class="line"><span>要在JavaScript中读取这些属性的值，可以使用getAttribute()，但是规范定义了一种更简单的方法：使用dataset属性</span></span></code></pre></div><h3 id="output-tag" tabindex="-1">output tag <a class="header-anchor" href="#output-tag" aria-label="Permalink to &quot;output tag&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;output&gt;标签表示运算的结果。通常，此元素定义一个区域，该区域将用于显示某些计算得出的文本。</span></span></code></pre></div><h3 id="datalist" tabindex="-1">datalist <a class="header-anchor" href="#datalist" aria-label="Permalink to &quot;datalist&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;datalist&gt;标签指定了预先定义的选项列表，并允许用户添加更多。它提供了一项autocomplete功能，使您可以提前输入所需的选项。</span></span>
<span class="line"><span>与传统&lt;select&gt;-&lt;option&gt;标签有何不同？Select标记用于从选项中选择一个或多个项目，您需要浏览列表以进行选择。Datalist是具有自动完成支持的高级功能。也就是说Datalist标签不仅可以选择，还可以输入</span></span></code></pre></div><h3 id="range-slider" tabindex="-1">range(slider) <a class="header-anchor" href="#range-slider" aria-label="Permalink to &quot;range(slider)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>range具有滑块，范围选择的输入类型</span></span></code></pre></div><h3 id="meter" tabindex="-1">meter <a class="header-anchor" href="#meter" aria-label="Permalink to &quot;meter&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用&lt;meter&gt;标签测量给定范围内的数据。</span></span>
<span class="line"><span>请勿将&lt;meter&gt;标签用于进度条。我们有&lt;Progress&gt;HTML5的标记。</span></span></code></pre></div>`,45)]))}const b=e(l,[["render",i]]);export{u as __pageData,b as default};
